// // This module implements a 2-to-1 multiplexer that selects between two inputs x and y based on the selection signal s. When s is 0, the output m is set to the value of y; when s is 1, the output m is set to the value of x.
module top_module(
    input x, y, s,
    output reg m
    );always @(x, y, s)
    begin
        case(s)
            0: m = x;
            1: m = y;
        endcase
    end

endmodule
